package com.onenation.recommender
import android.app.AlarmManager; import android.app.PendingIntent; import android.content.BroadcastReceiver; import android.content.Context; import android.content.Intent; import android.os.Build
class RetryAlarmReceiver : BroadcastReceiver() { override fun onReceive(c: Context, i: Intent?) { applyAutoDelete(c) }; companion object { fun schedule(c: Context) { val am=c.getSystemService(Context.ALARM_SERVICE) as AlarmManager; val i=Intent(c,RetryAlarmReceiver::class.java); val f=if(Build.VERSION.SDK_INT>=Build.VERSION_CODES.M) PendingIntent.FLAG_IMMUTABLE or PendingIntent.FLAG_UPDATE_CURRENT else PendingIntent.FLAG_UPDATE_CURRENT; val pi=PendingIntent.getBroadcast(c,5001,i,f); val cal=java.util.Calendar.getInstance().apply{set(java.util.Calendar.HOUR_OF_DAY,2);set(java.util.Calendar.MINUTE,0);set(java.util.Calendar.SECOND,0);if(before(java.util.Calendar.getInstance()))add(java.util.Calendar.DAY_OF_MONTH,1)}; am.setRepeating(AlarmManager.RTC_WAKEUP,cal.timeInMillis,AlarmManager.INTERVAL_DAY,pi) }; fun applyAutoDelete(c: Context) { when(ContactManager.getAutoDeleteSetting(c)){"daily"->ContactManager.deleteInstalledNumbers(c);"weekly"->{if(java.util.Calendar.getInstance().get(java.util.Calendar.DAY_OF_WEEK)==java.util.Calendar.SUNDAY)ContactManager.deleteInstalledNumbers(c)};"monthly"->{if(java.util.Calendar.getInstance().get(java.util.Calendar.DAY_OF_MONTH)==1)ContactManager.deleteInstalledNumbers(c)}} } } }
